455	var measurementPattern = regexp.MustCompile(`(?i)(-?\d+(?:\.\d+)?)(?:\s*)(ms|s|sec|seconds?)?`)
456	
457	func normalizeMeasurement(stdout string) (float64, string) {
458		trimmed := strings.TrimSpace(stdout)
459		if trimmed == "" {
460			return 0, ""
461		}
462		if value, unit, ok := parseJSONMeasurement(trimmed); ok {
463			return value, unit
464		}
465		if value, unit, ok := parseTextMeasurement(trimmed); ok {
466			return value, unit
467		}
468		return 0, ""
469	}
470	
471	func parseJSONMeasurement(text string) (float64, string, bool) {
472		var obj map[string]any
473		if err := json.Unmarshal([]byte(text), &obj); err != nil {
474			return 0, "", false
475		}
476		if raw, ok := obj["value"]; ok {
477			switch v := raw.(type) {
478			case float64:
479				unit, _ := obj["unit"].(string)
480				return v, unit, true
481			case string:
482				if parsed, err := strconv.ParseFloat(v, 64); err == nil {
483					unit, _ := obj["unit"].(string)
484					return parsed, unit, true
485				}
486			}
487		}
488		return 0, "", false
489	}
490	
491	func parseTextMeasurement(text string) (float64, string, bool) {
492		match := measurementPattern.FindStringSubmatch(text)
493		if len(match) < 2 {
494			return 0, "", false
495		}
496		value, err := strconv.ParseFloat(match[1], 64)
497		if err != nil {
498			return 0, "", false
499		}
500		unit := ""
501		if len(match) >= 3 {
502			unit = strings.ToLower(match[2])
503		}
504		return value, unit, true
505	}
506	
507	func metricStatusForRun(status string) string {
508		if status == StatusSuccess {
509			return "pass"
510		}
511		return "fail"
512	}
